import React, { createContext, useContext, useState, useEffect } from 'react';
import { useAuth } from './AuthContext';
import { cartService } from '../services/cartService';
import { cartItemService } from '../services/cartItemService';
import toast from 'react-hot-toast';

const CartContext = createContext();
export const useCart = () => useContext(CartContext);

export const CartProvider = ({ children }) => {
  const { user } = useAuth();
  const [cart, setCart] = useState(null);
  const [cartItems, setCartItems] = useState([]);
  const [cartCount, setCartCount] = useState(0);

  useEffect(() => {
    if (user) loadCart();
    else { setCart(null); setCartItems([]); setCartCount(0); }
  }, [user]);

  const loadCart = async () => {
    try {
      const userCart = await cartService.getCartByUserId(user.userId || user.user_id);
      if (userCart) {
        setCart(userCart);
        const items = await cartItemService.getItemsByCartId(userCart.cartId || userCart.cart_id);
        setCartItems(items || []);
        setCartCount((items || []).reduce((sum, i) => sum + i.quantity, 0));
      }
    } catch {}
  };

  const addToCart = async (product) => {
    if (!user) { toast.error('Please login to add items'); return; }
    try {
      let userCart = cart;
      if (!userCart) {
        userCart = await cartService.createCart({ userId: user.userId || user.user_id, totalAmount: 0, discount: 0 });
        setCart(userCart);
      }
      const existing = cartItems.find(i => (i.productId || i.product_id) === (product.productId || product.product_id));
      if (existing) {
        await cartItemService.updateCartItem(existing.cartItemId || existing.cart_item_id, { ...existing, quantity: existing.quantity + 1 });
      } else {
        await cartItemService.addCartItem({
          cartId: userCart.cartId || userCart.cart_id,
          productId: product.productId || product.product_id,
          quantity: 1,
          price: product.productPrice || product.product_price
        });
      }
      await loadCart();
      toast.success(`${product.productName || product.product_name} added to cart! 🛒`);
    } catch { toast.error('Failed to add item'); }
  };

  const removeFromCart = async (cartItemId) => {
    try {
      await cartItemService.removeCartItem(cartItemId);
      await loadCart();
      toast.success('Item removed');
    } catch { toast.error('Failed to remove item'); }
  };

  return (
    <CartContext.Provider value={{ cart, cartItems, cartCount, addToCart, removeFromCart, loadCart }}>
      {children}
    </CartContext.Provider>
  );
};
